# %% ../nbs/101_utils.ipynb #0d2cb37f
def satvap(
    tc: float,  # Temperature (degC)
) -> tuple[float, float]:
    """Compute saturation vapor pressure (esat) and the rate of change in
    saturation vapor pressure with respect to temperature (dsat = d(esat)/dT).

    Polynomial approximations are from: Flatau et al. (1992) Polynomial fits to
    saturation vapor pressure.
    Journal of Applied Meteorology 31:1507-1513. Input temperature is Celsius.

    __Parameters:__

    - tc: Temperature (degC).

    __Returns:__

    - esat: Saturation vapor pressure (Pa)
    - desat: d(esat)/dT (Pa/K).

    Parameters
    ----------
    tc : float
        Temperature (degC).

    Returns
    -------
    esat,dsat : float
        esat: Saturation vapor pressure (Pa), desat: d(esat)/dT (Pa/K).
    """

    # Regression coefficients

    # Saturation vapor pressure over liquid water

    # For water vapor (temperature range is 0C to 100C)

    a0 = 6.11213476
    a1 = 0.444007856
    a2 = 0.143064234e-01
    a3 = 0.264461437e-03
    a4 = 0.305903558e-05
    a5 = 0.196237241e-07
    a6 = 0.892344772e-10
    a7 = -0.373208410e-12
    a8 = 0.209339997e-15

    # Derivative d(esat)/dT over liquid water
    b0 = 0.444017302
    b1 = 0.286064092e-01
    b2 = 0.794683137e-03
    b3 = 0.121211669e-04
    b4 = 0.103354611e-06
    b5 = 0.404125005e-09
    b6 = -0.788037859e-12
    b7 = -0.114596802e-13
    b8 = 0.381294516e-16

    # Saturation vapor pressure over ice (вҲ’75В°C to 0В°C)
    c0 = 6.11123516
    c1 = 0.503109514
    c2 = 0.188369801e-01
    c3 = 0.420547422e-03
    c4 = 0.614396778e-05
    c5 = 0.602780717e-07
    c6 = 0.387940929e-09
    c7 = 0.149436277e-11
    c8 = 0.262655803e-14

    # derivative d(esat)/dT over ice
    d0 = 0.503277922
    d1 = 0.377289173e-01
    d2 = 0.126801703e-02
    d3 = 0.249468427e-04
    d4 = 0.313703411e-06
    d5 = 0.257180651e-08
    d6 = 0.133268878e-10
    d7 = 0.394116744e-13
    d8 = 0.498070196e-16

    # Limit temperature to -75C to 100C
    tc = min(tc, 100.0)
    tc = max(tc, -75.0)

    # Saturation vapor pressure (esat, mb) and derivative (desat, mb)

    if tc >= 0:
        # Horner's method
        esat = a0 + tc * (
            a1
            + tc
            * (a2 + tc * (a3 + tc * (a4 + tc * (a5 + tc * (a6 + tc * (a7 + tc * a8))))))
        )

        desat = b0 + tc * (
            b1
            + tc
            * (b2 + tc * (b3 + tc * (b4 + tc * (b5 + tc * (b6 + tc * (b7 + tc * b8))))))
        )
    else:
        esat = c0 + tc * (
            c1
            + tc
            * (c2 + tc * (c3 + tc * (c4 + tc * (c5 + tc * (c6 + tc * (c7 + tc * c8))))))
        )

        desat = d0 + tc * (
            d1
            + tc
            * (d2 + tc * (d3 + tc * (d4 + tc * (d5 + tc * (d6 + tc * (d7 + tc * d8))))))
        )

    # Convert from mb to Pa
    esat *= 100.0
    desat *= 100.0

    return esat, desat

# %% ../nbs/101_utils.ipynb #7f4c99f1
def latvap(tc: float, mmh2o: float) -> float:
    """
    Latent heat of vaporization (J/mol) at temperature tc (degC).

    __Parameters:__

    - tc: Temperature (degC).
    - mmh2o: Molecular mass of water (kg/mol).

    __Returns:__

    - val: Latent heat of vaporization (J/mol).

    Parameters
    ----------
    tc : float
        Temperature (degC).
    mmh2o : float
        Molecular mass of water (kg/mol).

    Returns
    -------
    val : float
        Latent heat of vaporization (J/mol).
    """
    val = 2501.6 - 2.3773 * tc  # J/g
    val = val * 1000.0  # J/g -> J/kg
    val = val * mmh2o  # J/kg -> J/mol
    return val

# %% ../nbs/101_utils.ipynb #79ca012c
def calc_radiative_forcing_qa(solar_down, leaf, ground_albedo, ground_lw, irsky):
    """
    Calculate leaf radiative forcing Qa (Equation 10.3).

    Compute the total radiation absorbed by a leaf from solar (visible and
    near-infrared wavebands) and longwave (sky and ground) sources. Solar
    radiation is split equally between visible and near-infrared wavebands,
    and includes both direct and ground-reflected components.

    Implements Equation (10.3) from Bonan (2019):

        Qa = ОЈ_Оӣ SвҶ“_Оӣ (1 + ПҒg_Оӣ)(1 - ПҒв„“_Оӣ - П„в„“_Оӣ) + Оөв„“ (LвҶ“sky + LвҶ‘g)

    where Оӣ denotes visible and near-infrared wavebands, ПҒg is ground
    albedo, ПҒв„“ and П„в„“ are leaf reflectance and transmittance, and Оөв„“ is
    leaf emissivity. The factor (1 + ПҒg) accounts for solar radiation
    striking the upper leaf surface directly plus radiation reflected
    from the ground striking the lower surface.

    __Parameters:__

    - solar_down: Total downward solar radiation incident on the leaf (W/m2).
                Split equally between visible and near-infrared wavebands.

    - leaf: Leaf object with the following attributes:
        - rho: Leaf reflectance for visible and near-infrared wavebands (-).
        - tau: Leaf transmittance for visible and near-infrared wavebands (-).
        - emiss: Leaf emissivity (-).

    - ground_albedo: Ground surface albedo for visible and near-infrared
    wavebands (-).

    - ground_lw: Upward longwave radiation emitted by the ground surface (W/m2).

    - irsky: Downward atmospheric longwave radiation (W/m2).

    __Returns:__

    - qa: Leaf radiative forcing (W/m2 leaf). Sum of absorbed solar radiation
        across both wavebands and absorbed longwave radiation from sky and
        ground.

    Parameters
    ----------
    solar_down : float
        Total downward solar radiation incident on the leaf (W/m2).
        Split equally between visible and near-infrared wavebands.
    leaf : Leaf
        Leaf object with the following attributes:
        - rho : list[float]
            Leaf reflectance for visible and near-infrared wavebands (-).
        - tau : list[float]
            Leaf transmittance for visible and near-infrared wavebands (-).
        - emiss : float
            Leaf emissivity (-).
    ground_albedo : list[float]
        Ground surface albedo for visible and near-infrared wavebands (-).
    ground_lw : float
        Upward longwave radiation emitted by the ground surface (W/m2).
    irsky : float
        Downward atmospheric longwave radiation (W/m2).

    Returns
    -------
    qa : float
        Leaf radiative forcing (W/m2 leaf). Sum of absorbed solar radiation
        across both wavebands and absorbed longwave radiation from sky and
        ground.


    """
    qa = 0.0

    # Solar radiation contribution (sum over vis and nir wavebands)
    for each_wv in range(2):
        # Half of total solar in each waveband
        s_wv = 0.5 * solar_down
        absorptance = 1.0 - leaf.rho[each_wv] - leaf.tau[each_wv]

        # Direct + ground-reflected
        incident = s_wv * (1.0 + ground_albedo[each_wv])
        qa += incident * absorptance

    # Longwave contribution (absorbed by both surfaces)
    qa += leaf.emiss * (irsky + ground_lw)

    return qa

# %% ../nbs/101_utils.ipynb #d2521114
def arrhenius_function(tl, ha):
    """
    Temperature response function used in `leaf_photosynthesis()`

    Follows Eq 11.34:

        f(t) = exp((deltaHa/298.15*r) * (1-298.15/Tl))

    where deltaHa is the activation energy (J molвҖ“1), Tl is the leaf temperature
    and r is the Universal gas constant (J/K/mol)

    __Parameters:__

    - tl: Leaf Temperature (K)
    - ha: Activation Energy (deltaHa). This parameter controls how sensible each
    enzyme is to warming. A high deltaHa means the enzyme's speed changes
    dramatically with temperature; a low deltaHa means it's more stable.

    At 25В°C (298.15 K), the function returns exactly 1.0, that's the reference
    point. Above 25В°C, it returns values greater than 1 (faster). Below 25В°C,
    values less than 1 (slower).

    Parameters
    ----------
    ha : float
        Activation Energy (J molвҖ“1)
    tl : float
        Leaf Temperature (K)

    Returns
    -------
    fc: float
        Scaling factor that equals 1.0 at 25В°C, greater than 1.0 above 25В°C, and less than 1.0 below 25В°C.

    """
    return np.exp(
        ha / (PhysCon.rgas * (PhysCon.tfrz + 25)) * (1 - (PhysCon.tfrz + 25) / tl)
    )

# %% ../nbs/101_utils.ipynb #6566a7be
def inhibition_function(tl, hd, se, fc):
    """
    High-temperature inhibition function used in `leaf_photosysthesis()`.
    This function represents thermal breakdown of biochemical processes.

    Follows Eq 11.36:

                1 + exp[(298.15В·О”S - О”Hd) / (298.15В·R)]
    fH(Tl) =  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
                  1 + exp[(О”SВ·Tl - О”Hd) / (RВ·Tl)]

    where deltaHd is the deactivation energy (J mol-1),
    Tl is the leaf temperature, deltaS is an entropy term and r is the
    Universal gas constant (J/K/mol).

    The combination arrhenius_function() * inhibition_function() creates the
    peaked response shown in the textbook's Figure 11.3 вҖ” activity rises,
    peaks at an optimum, then falls.


    __Parameters:__

    - tl : Leaf Temperature (K)
    - hd : Deactivation Energy (J molвҖ“1)
    - se : Entropy term (MISSING UNITS)
    - fc : Overheat Protection (MISSING UNITS)

    Parameters
    ----------
    tl : float
          Leaf Temperature (K)
    hd : float
         Deactivation Energy (J molвҖ“1)
    se : float
          Entropy term (MISSING UNITS)
    fc : float
          Overheat Protection (MISSING UNITS)


    """
    return fc / (1 + np.exp((-hd + se * tl) / (PhysCon.rgas * tl)))

# %% ../nbs/101_utils.ipynb #1b8baf5c
def brent_root(
    func,
    physcon: PhysCon,
    atmos: Atmos,
    leaf: Leaf,
    flux: Flux,
    xa: float,
    xb: float,
    tol: float,
) -> tuple[Flux, float]:
    """
    Brent's root finder

    Use Brent's method to find the root of a function, which is known to exist
    between xa and xb. The root is updated until its accuracy is tol. func is
    the name of the function to solve. The variable root is returned as the root
    of the function. The function being evaluated has the definition statement:

    function [flux, fx] = func (physcon, atmos, leaf, flux, x)

    The function func is exaluated at x and the returned value is fx. It uses
    variables in the physcon, atmos, leaf, and flux structures. These are passed
    in as input arguments. It also calculates values for variables in the flux
    structure so this must be returned in the function call as an output
    argument.

    Parameters
    ----------
    func : callable
        Function with signature func(physcon, atmos, leaf, flux, x) -> (flux, fx)
    xa, xb : float
        Bracket for the root.
    tol : float
        Tolerance for the root.

    Returns
    -------
    flux : Flux
        Updated flux structure.
    root : float
        Root of the function.
    """

    # Evaluate func at xa and xb and make sure the root is bracketed ------------

    # Left bracket (i.e gs = 0.002)
    a = xa

    # Right bracket (i.e gs = 2.0)
    b = xb

    # If both ends have the same sign, the root isn't between them
    flux, fa = func(physcon, atmos, leaf, flux, a)
    flux, fb = func(physcon, atmos, leaf, flux, b)

    if (fa > 0 and fb > 0) or (fa < 0 and fb < 0):
        raise RuntimeError("brent_root error: root must be bracketed")

    # Initialising the third point ----------------------------------------------
    c = b
    fc = fb
    d = b - a
    e = d

    # Initialize iteration ------------------------------------------------------

    # Maximum number of iterations
    itmax = 50

    # Relative error tolerance
    eps1 = 1e-08

    # Iterative root calculation ------------------------------------------------
    # In Each iteration, the algorithm goes through several decision stages
    for iteration in range(1, itmax + 1):
        # Ensure b and c bracket the root
        # If b and c ended up on the same side (same sign),
        # replace c with a вҖ” restoring the bracket.
        if (fb > 0 and fc > 0) or (fb < 0 and fc < 0):
            c = a
            fc = fa
            d = b - a
            e = d

        # Keep b as the best guess
        # If c is actually closer to zero than b, swap them. The variable b
        # should always be the best current estimate
        if abs(fc) < abs(fb):
            a = b
            b = c
            c = a
            fa = fb
            fb = fc
            fc = fa

        # Check if it is done
        tol1 = 2.0 * eps1 * abs(b) + 0.5 * tol
        xm = 0.5 * (c - b)

        # Check to end iteration
        # If the bracket is tiny (|c вҲ’ b| is within tolerance) or we've hit the
        # root exactly (fb = 0), break
        if abs(xm) <= tol1 or fb == 0:
            break

        # Try the fast method or fall back to bisection
        # "Should interpolation or bisect be used?" The conditions check two
        # things: (1) the previous step was large enough to be meaningful, and
        # (2) we're making progress (|fb| < |fa|).
        if abs(e) >= tol1 and abs(fa) > abs(fb):
            # If yes вҖ” try interpolation:
            s = fb / fa
            if a == c:
                # Secant method (Equation A.32 from the textbook)
                # Draw a straight line through (a, fa) and (b, fb) and find
                # where it crosses zero
                p = 2.0 * xm * s
                q = 1.0 - s
            else:
                # Inverse quadratic interpolation
                # Fitting a parabola through the three points and find its zero
                # cross
                q = fa / fc
                r = fb / fc
                p = s * (2.0 * xm * q * (q - r) - (b - a) * (r - 1.0))
                q = (q - 1.0) * (r - 1.0) * (s - 1.0)

            if p > 0:
                q = -q
            p = abs(p)

            if 2.0 * p < min(3.0 * xm * q - abs(tol1 * q), abs(e * q)):
                e = d

                # Accept the interpolation step
                d = p / q
            else:
                # Reject it, fall back to bisection
                d = xm
                e = d
        else:
            # Bisection: step to midpoint
            d = xm
            e = d

        # Take the step
        a = b
        fa = fb

        if abs(d) > tol1:
            b = b + d
        else:
            if xm >= 0:
                b = b + abs(tol1)
            else:
                b = b - abs(tol1)

        flux, fb = func(physcon, atmos, leaf, flux, b)

        # Check to end iteration
        if fb == 0:
            break

        # Check to see if failed to converge
        if iteration == itmax:
            raise RuntimeError(
                "brent_root error: Maximum number of iterations exceeded"
            )

    root = b
    return flux, root

