def time_to_float(time_str):
    h, m = map(int, time_str.split(":"))
    return h + m / 60

# %% ../nbs/101_utils.ipynb #6f299dfe
def diurnal_par(hour, par_max=800.0, sunrise=6.0, sunset=20.0):
    """
    Shortwave radiation following a sinusoidal daytime curve.

    PAR = par_max * sin(ПҖ * (hour - sunrise) / daylength)

    Returns total shortwave in W/mВІ (split 50/50 VIS/NIR later).
    At night (before sunrise or after sunset): returns 0.

    Parameters
    ----------
    hour : float
        Hour of day (0-24). E.g., 6.5 = 6:30 AM.
    par_max : float
        Peak shortwave radiation at solar noon (W/m2).
    sunrise, sunset : float
        Hours of sunrise and sunset.
    """
    daylength = sunset - sunrise
    if sunrise <= hour <= sunset:
        return par_max * np.sin(np.pi * (hour - sunrise) / daylength)
    else:
        return 0.0

# %% ../nbs/101_utils.ipynb #d2256e7f
def diurnal_temperature(hour, t_mean=25.0, t_amp=7.0, t_min_hour=5.5):
    """
    Air temperature following a sinusoidal curve with minimum at dawn.

    Tair = t_mean + t_amp * sin(2ПҖ * (hour - t_min_hour) / 24 - ПҖ/2)

    This gives:
        Minimum at t_min_hour (dawn, ~5:30)
        Maximum at t_min_hour + 6 = 11:30... but real Tmax lags to ~14:00.

    To get the ~2-hour lag, we shift the phase:
        Tair = t_mean + t_amp * sin(2ПҖ * (hour - t_max_hour) / 24)
    where t_max_hour = 14.0 (2 PM), so minimum is at 14 - 12 = 2 AM...
    That's too early for Tmin.

    Better approach: use an asymmetric function.
    Simpler: just use a sine with Tmax at 14:00.
        Tair = t_mean + t_amp * sin(2ПҖ * (hour - 8.0) / 24)
    This gives Tmax at 14:00 and Tmin at 2:00 AM.
    At dawn (6:00): T = 25 + 7*sin(2ПҖ*(-2)/24) = 25 + 7*sin(-ПҖ/6) = 25 - 3.5 = 21.5В°C
    At noon (12:00): T = 25 + 7*sin(2ПҖ*4/24) = 25 + 7*sin(ПҖ/3) = 25 + 6.06 = 31.1В°C
    At 14:00: T = 25 + 7*sin(2ПҖ*6/24) = 25 + 7*sin(ПҖ/2) = 32В°C вҶҗ max
    At 20:00: T = 25 + 7*sin(2ПҖ*12/24) = 25 + 0 = 25В°C

    That looks realistic!
    """
    # Phase shift: maximum at hour 14
    phase = 2.0 * np.pi * (hour - 8.0) / 24.0
    return t_mean + t_amp * np.sin(phase)

# %% ../nbs/101_utils.ipynb #17e1217e
def diurnal_relhum(hour, rh_mean=65.0, rh_amp=20.0):
    """
    Relative humidity, anti-correlated with temperature.

    RH is highest at dawn and lowest in the afternoon.
    We use the OPPOSITE phase of temperature:
        RH = rh_mean - rh_amp * sin(2ПҖ * (hour - 8) / 24)

    This gives:
        Maximum at 2:00 AM: 65 + 20 = 85%
        At dawn (6:00): 65 + 10 = 75%
        At noon (12:00): 65 - 17.3 = 47.7%
        Minimum at 14:00: 65 - 20 = 45%
        At sunset (20:00): 65%

    The negative sign flips the phase relative to temperature.
    """
    phase = 2.0 * np.pi * (hour - 8.0) / 24.0
    rh = rh_mean - rh_amp * np.sin(phase)

    # Physical bounds
    return np.clip(rh, 20.0, 95.0)

# %% ../nbs/101_utils.ipynb #30708e5f
def compute_theta_at_psi_VG(
    PsiTarget: npt.ArrayLike,
    thetaRes: npt.ArrayLike,
    thetaSat: npt.ArrayLike,
    alpha_vg: npt.ArrayLike,
    n_vg: npt.ArrayLike,
) -> np.ndarray:
    """
    Compute volumetric water content at a given soil water potential
    using the van Genuchten (1980) water retention model.

    The van Genuchten closed-form retention curve relates the
    effective saturation *S_e* to the matric potential *ПҲ* (suction)
    via two shape parameters Оұ and n:

    .. math::

        \\theta(\\psi) = \\theta_r
            + \\frac{\\theta_s - \\theta_r}
                   {\\bigl[1 + (\\alpha \\,|\\psi|)^{n}\\bigr]^{m}}

    where:

    - *Оё_s* is the saturated water content (mВі/mВі),
    - *Оё_r* is the residual water content (mВі/mВі),
    - *Оұ* is related to the inverse of the air-entry pressure (cmвҒ»В№),
    - *n* is the pore-size distribution index (dimensionless, n > 1),
    - *m = 1 вҲ’ 1/n* (Mualem constraint).

    .. note::
       In SurEau-Ecos, *PsiTarget* is supplied in **MPa** (positive
       suction convention) and is converted internally to the hPa
       (вүЎ cm HвӮӮO) domain expected by the VG Оұ parameter via
       multiplication by 10 000.

    Parameters
    ----------
    PsiTarget : array_like
        Target soil water potential in **MPa** (positive = suction).
        For example, 1.5 MPa corresponds to the conventional wilting
        point.
    thetaRes : array_like
        Residual volumetric water content Оё_r (mВі/mВі).
    thetaSat : array_like
        Saturated volumetric water content Оё_s (mВі/mВі).
    alpha_vg : array_like
        Van Genuchten Оұ parameter (cmвҒ»В№).
    n_vg : array_like
        Van Genuchten n parameter (dimensionless).

    Returns
    -------
    np.ndarray
        Volumetric water content Оё at the target potential (mВі/mВі).

    References
    ----------
    van Genuchten, M.Th. (1980). A closed-form equation for
    predicting the hydraulic conductivity of unsaturated soils.
    *Soil Sci. Soc. Am. J.*, 44(5), 892вҖ“898.
    """
    PsiTarget = np.asarray(PsiTarget, dtype=np.float64)
    thetaRes = np.asarray(thetaRes, dtype=np.float64)
    thetaSat = np.asarray(thetaSat, dtype=np.float64)
    alpha_vg = np.asarray(alpha_vg, dtype=np.float64)
    n_vg = np.asarray(n_vg, dtype=np.float64)

    m = 1.0 - 1.0 / n_vg
    # MPa вҶ’ hPa (= cm HвӮӮO): Г—10 000
    psi_hPa = np.abs(PsiTarget) * 10_000.0
    return thetaRes + (thetaSat - thetaRes) / (1.0 + (alpha_vg * psi_hPa) ** n_vg) ** m

# %% ../nbs/101_utils.ipynb #1fc58075
def compute_theta_at_psi_Campbell(
    PsiTarget: npt.ArrayLike,
    thetaSat: npt.ArrayLike,
    psie: npt.ArrayLike,
    b: npt.ArrayLike,
) -> np.ndarray:
    """
    Compute volumetric water content at a given soil water potential
    using the inverse Campbell (1974) retention curve.

    Starting from the Campbell retention equation:

    .. math::

        \\psi = \\psi_e \\left(\\frac{\\theta}{\\theta_s}\\right)^{-b}

    algebraic inversion yields the water content at a target
    potential *ПҲ_target*:

    .. math::

        \\theta(\\psi_{\\text{target}}) = \\theta_s
            \\left(
                \\frac{-\\psi_{\\text{target}}}{-\\psi_e}
            \\right)^{-1/b}

    The double negation ensures correct handling of the sign
    convention (both *ПҲ_target* and *ПҲ_e* are negative / suction).

    Parameters
    ----------
    PsiTarget : array_like
        Target soil water potential (MPa, **negative** = suction).
    thetaSat : array_like
        Saturated volumetric water content Оё_s (mВі/mВі).
    psie : array_like
        Air-entry potential ПҲ_e (MPa, **negative**).
    b : array_like
        Campbell shape parameter (positive, dimensionless).

    Returns
    -------
    np.ndarray
        Volumetric water content Оё at the target potential (mВі/mВі).

    Notes
    -----
    For very dry conditions (|ПҲ_target| вү« |ПҲ_e|), the returned
    water content can approach zero.  In the SurEau model this value
    is used as the "residual capacity" for the Campbell PTF (e.g.
    Оё at вҲ’100 MPa serves as an approximate Оё_r).

    References
    ----------
    Campbell, G.S. (1974). A simple method for determining
    unsaturated conductivity from moisture retention data.
    *Soil Science*, 117(6), 311вҖ“314.
    """
    PsiTarget = np.asarray(PsiTarget, dtype=np.float64)
    thetaSat = np.asarray(thetaSat, dtype=np.float64)
    psie = np.asarray(psie, dtype=np.float64)
    b = np.asarray(b, dtype=np.float64)

    return thetaSat * (-PsiTarget / -psie) ** (-1.0 / b)

# %% ../nbs/101_utils.ipynb #227e9a7b
def flux_leaf_to_stand(x, dt, LAI=1.0):
    """mmol/mВІleaf/s  вҶ’  mm/mВІsoil over dt hours."""
    return x * LAI * dt * 0.0648

# %% ../nbs/101_utils.ipynb #50277bb1
def flux_mm_to_mmol_m2leaf_s(x, dt, LAI):
    """mm/mВІsoil over dt hours вҶ’ mmol/mВІleaf/s."""
    if LAI > 0:
        return 1e6 * x / (LAI * dt * 3600 * 18)
    return np.zeros_like(x) if hasattr(x, "__len__") else 0.0

# %% ../nbs/101_utils.ipynb #74679486
def convert_FtoV(x, RFC, layer_thickness):
    """Volumetric water content (mВі/mВі) вҶ’ water height (mm)."""
    return x * (1.0 - RFC / 100.0) * layer_thickness * 1000.0

# %% ../nbs/101_utils.ipynb #33fa81ef
def compute_VPD(RH, T):
    """Compute VPD [kPa] from relative humidity [%] and temperature [В°C]."""
    esat = 6.108 * np.exp(17.27 * T / (237.2 + T)) * 100.0  # Pa
    ea = RH * esat / 100.0
    vpd = (esat - ea) / 1000.0  # kPa
    if np.isscalar(vpd):
        return max(0.0, vpd)
    vpd[vpd < 0] = 0.0
    return vpd

# %% ../nbs/101_utils.ipynb #78fa9781
def compute_slope_sat(T):
    """Slope of saturation vapour pressure curve [kPa/В°C]."""
    return 4098 * 0.6108 * np.exp(17.27 * T / (T + 237.3)) / (T + 237.3) ** 2

# %% ../nbs/101_utils.ipynb #4c22e4f2
def compute_ETP_PT(T_mean, net_radiation, PT_coeff, G=0.0):
    """Priestley-Taylor PET [mm]."""
    gamma = 0.0666
    lam = 2.45
    s = compute_slope_sat(T_mean)
    return PT_coeff * (s / (s + gamma)) * ((net_radiation - G) / lam)

# %% ../nbs/101_utils.ipynb #24349b02
def compute_ETP_PM(T_mean, net_radiation, u, vpd, G=0.0):
    """Penman-Monteith PET [mm]."""
    gamma = 0.0666
    delta = (
        4098
        * 0.6108
        * np.exp(17.27 * T_mean / (T_mean + 237.3))
        / (T_mean + 237.3) ** 2
    )
    u2 = u * (4.87 / np.log(67.8 * 10 - 5.42))
    N1 = 0.408 * delta * net_radiation
    N2 = gamma * (37 / (T_mean + 273)) * u2 * vpd
    D = delta + gamma * (1 + 0.34 * u2)
    return (N1 + N2) / D

# %% ../nbs/101_utils.ipynb #51757fa6
def Rg_MJ_to_Watt(Rg_MJ, N_hours):
    """MJ вҶ’ W/mВІ given N_hours."""
    return Rg_MJ * (1e6 / (N_hours * 3600))

# %% ../nbs/101_utils.ipynb #213da335
def Rg_Watt_to_PPFD(Rg_W, J_to_mol=4.6, frac_PAR=0.5):
    """W/mВІ вҶ’ Вөmol/mВІ/s PPFD."""
    return Rg_W * frac_PAR * J_to_mol

# %% ../nbs/101_utils.ipynb #a2f6daae
def declination(DOY):
    """Solar declination [rad]."""
    c1 = 0.398749068925246
    c2 = 2 * np.pi / 365
    c3 = 80
    x = c1 * np.sin((DOY - c3) * c2)
    return np.arctan(x / np.sqrt(1 - x * x))

# %% ../nbs/101_utils.ipynb #393ebc30
def potential_PAR(time_of_day, lat, DOY):
    """Potential PAR [W/mВІ] at given hours, latitude, and DOY."""
    time_of_day = np.asarray(time_of_day, dtype=float)
    diffuse_frac = 0.1
    solar_const = 2084.0
    atten = -0.174353387144778
    decl = declination(DOY)
    pn = -np.cos(np.radians(lat))
    pz = np.sin(np.radians(lat))
    h_rad = (time_of_day - 6) * np.pi / 12
    se = np.cos(h_rad) * np.cos(decl)
    sn = -pz * np.sin(h_rad) * np.cos(decl) - pn * np.sin(decl)
    sz = -pn * np.sin(h_rad) * np.cos(decl) + pz * np.sin(decl)
    alt = np.arctan2(sz, np.sqrt(se**2 + sn**2))
    pfd = solar_const * np.exp(atten / np.sin(np.clip(alt, 1e-10, None)))
    pfd = np.where(alt < 0, 0.0, pfd)
    dpfd = np.where(alt < 0, 0.0, diffuse_frac * pfd)
    return dpfd + pfd * np.maximum(np.sin(alt), 0.0)

# %% ../nbs/101_utils.ipynb #090360f9
def daylength(latitude, JDay):
    """Compute sunrise [h], sunset [h], daylength [h]."""
    gamma = 2 * np.pi / 365 * (JDay - 1)
    delta_deg = (180 / np.pi) * (
        0.006918
        - 0.399912 * np.cos(gamma)
        + 0.070257 * np.sin(gamma)
        - 0.006758 * np.cos(2 * gamma)
        + 0.000907 * np.sin(2 * gamma)
        - 0.002697 * np.cos(3 * gamma)
        + 0.00148 * np.sin(3 * gamma)
    )
    cos_wo = (
        np.sin(np.radians(-0.8333))
        - np.sin(np.radians(latitude)) * np.sin(np.radians(delta_deg))
    ) / (np.cos(np.radians(latitude)) * np.cos(np.radians(delta_deg)))
    if cos_wo < -1:
        return 0.0, 24.0, 24.0  # polar day
    if cos_wo > 1:
        return 12.0, 12.0, 0.0  # polar night
    sunrise = 12 - np.degrees(np.arccos(cos_wo)) / 15
    sunset = 12 + np.degrees(np.arccos(cos_wo)) / 15
    return sunrise, sunset, sunset - sunrise

# %% ../nbs/101_utils.ipynb #ea14d8f5
def radiation_diurnal_pattern(time_sec, daylength_sec):
    """Fractional radiation at time_sec from sunrise, given daylength in seconds."""
    if daylength_sec <= 0:
        return 0.0
    ws = (daylength_sec / 3600.0) * (np.pi / 24.0)
    w = ws - (time_sec / daylength_sec) * (ws * 2.0)
    denom = np.sin(ws) - ws * np.cos(ws)
    if abs(denom) < 1e-30:
        return 0.0
    prop = ((np.pi / 24.0) * (np.cos(w) - np.cos(ws))) / denom
    return prop / 3600.0

# %% ../nbs/101_utils.ipynb #f5634022
def temperature_diurnal(
    time_sec, tmin, tmax, tmin_prev, tmax_prev, tmin_next, daylength_sec
):
    """Sinusoidal temperature disaggregation (McMurtrie et al. 1990)."""
    if time_sec < 0 or time_sec >= daylength_sec:
        t_fin = 86400.0 - daylength_sec
        if t_fin <= 0:
            t_fin = 1.0
        if time_sec < 0:
            t = time_sec + 86400.0 - daylength_sec
            return 0.5 * (tmax_prev + tmin_prev) * (1 - t / t_fin) + tmin * (t / t_fin)
        else:
            t = time_sec - daylength_sec
            return 0.5 * (tmax + tmin) * (1 - t / t_fin) + tmin_next * (t / t_fin)
    else:
        ct = np.cos(1.5 * np.pi * time_sec / daylength_sec)
        return 0.5 * (tmin + tmax - (tmax - tmin) * ct)

# %% ../nbs/101_utils.ipynb #dc0742c9
def rh_diurnal(temperature, tmin, tmax, rh_min, rh_max):
    """Linear RH disaggregation."""
    dT = tmax - tmin
    if abs(dT) < 1e-10:
        return 0.5 * (rh_min + rh_max)
    return rh_max + (temperature - tmin) / dT * (rh_min - rh_max)
